  1578→  /* Parses the next Jam expression in the input stream (assuming no tokne in that expression has yet been read) */
  1579→  private SymAST parseExp() {
  1580→    
  1581→    Token token = in.readToken();
  1582→    
  1583→    /* <exp> :: = if <exp> then <exp> else <exp>
  1584→                | let <prop-def-list> in <exp>
  1585→                | map <id-list> to <exp>
  1586→                | <term> { <biop> <term> }*  // (left associatively!)
  1587→    */
  1588→    
  1589→    if (token == ifKey) return parseIf();
  1590→    if (token == letrecKey) return parseLetRec();
  1591→    if (token == letccKey) return parseLetcc();
  1592→    if (token == letKey) return parseLet();
  1593→    if (token == mapKey) return parseMap();
  1594→    
  1595→    if (token == LeftBrace.ONLY) {
  1596→      SymAST[] exps = parseExps(SemiColon.ONLY,RightBrace.ONLY);   // including closing brace
  1597→      if (exps.length == 0) throw new ParseException("Illegal empty block");
  1598→      return new Block(exps);
  1599→    }
  1600→    
  1601→    SymAST exp = parseTerm(token);
  1602→    
  1603→    Token next = in.peek();
  1604→    while (next instanceof OpToken) {
  1605→      OpToken op = (OpToken) next;
  1606→      in.readToken(); // remove next from input stream
  1607→      if (! (op.isBinOp())) error(next, "binary operator");
  1608→      AST newTerm = parseTerm(in.readToken());
  1609→      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
  1610→//      System.err.println("exp updated to: " + exp);
  1611→      next = in.peek();
  1612→    }
  1613→//    System.err.println("parseTerm returning " + exp);
  1614→    return exp;
  1615→  }
