  1617→  private SymAST parseTerm(Token token) {
  1618→    
  1619→    /* <term>     ::= { <unop> } <term> | <constant> | <factor> {( <exp-list> )} 
  1620→       <constant> ::= <null> | <int> | <bool>
  1621→     */
