   462→    VarEnv newEnv = env();
   463→    Binding[] bindings = new Binding[n];
   464→    for (int i = n-1; i >= 0; i--) {
   465→      bindings[i] = new Binding(vars[i], exps[i].accept(this));  // bind var[i] to exps[i] in this evaluator
   466→      newEnv = newEnv.cons(bindings[i]);          
   467→    }
   468→    SymASTVisitor<JamVal> newEvalVisitor = newEvalVisitor(newEnv);
   469→    return l.body().accept(newEvalVisitor);
